function topKFrequent(nums, k) {
    let count = new Map();
    for (let num of nums) {
        count.set(num, (count.get(num) || 0) + 1);
    }
    let maxHeap = [...count.entries()];
    maxHeap.sort((a, b) => b[1] - a[1]);
    return maxHeap.slice(0, k).map(x => x[0]);
}

